AME=A.BUNKNAME  AND ZAC.ITEMNAME = AC.ITEMNAME  AND ZAA.COMPCODE=D.GTCOMPMASTID AND ZAA.FUELDATE <= A.TOKENDATE  )  )  AS FUELRATE2,I.BUNKNAME,I.BUNKNAME AS ACTIVE,                A.REMARKS ,'" + MON + "' AS TODATE ,A.TOTALKM AS ASPTBLVEHTOKENID1,F.MIDCARD AS LITRES1  FROM  ASPTBLVEHTOKEN A     JOIN ASPTBLVEHTOKENDET B ON A.ASPTBLVEHTOKENID=B.ASPTBLVEHTOKENID   AND A.TOKENCANCEL='F'   JOIN GTCOMPMAST D ON D.GTCOMPMASTID=A.COMPCODE  JOIN HREMPLOYMAST E ON E.HREMPLOYMASTID=A.EMPNAME       JOIN hremploydetails F ON F.HREMPLOYMASTID=E.HREMPLOYMASTID  join HRVEHTYPEMAST G on G.HRVEHTYPEMASTid=A.VEHICLETYPE JOIN GTGENITEMMAST H ON H.GTGENITEMMASTID=B.ITEMNAME  JOIN ASPTBLPETMAS I ON I.COMPCODE=D.GTCOMPMASTID AND I.COMPCODE=A.COMPCODE   AND  I.ASPTBLPETMASID=A.BUNKNAME join GTDEPTDESGMAST j on   J.GTDEPTDESGMASTID=F.DEPTNAME ) X WHERE X.COMPCODE='" + Class.Users.HCompcode + "' AND   X.TOKENDATE between TO_DATE('" + frmdate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy') AND TO_DATE('" + todate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy')  AND X.BUNKNAME='" + combobunk.Text + "' GROUP BY X.ASPTBLVEHTOKENID, X.COMPCODE,X.TOKENNO,  X.TOKENDATE,X.VEHICLENO, X.VEHTYPE ,X.FNAME, X.DEPT,  X.ITEMNAME,X.LITRES, X.FUELRATE2,X.BUNKNAME,X.ACTIVE,X.REMARKS,X.TODATE,X.ASPTBLVEHTOKENID1,X.LITRES1 ORDER BY 1";
