        public void DownLoads()
        {           

            if (comboformate.Text != "")
            {

                DialogResult result = MessageBox.Show("Do you want to '" + comboformate.Text + "' Formate ??", "" + comboformate.Text + "PRINT OUT", MessageBoxButtons.OKCancel, MessageBoxIcon.Information);
                if (result.Equals(DialogResult.OK))
                {
                    if (combocompcode.Text == "AGF")
                    {
                        switch (comboformate.Text)
                        {
                            case "Word":
                                cv.ExportToDisk(ExportFormatType.WordForWindows, "d:\\'" + combocompcode.Text + "'CompanyVehicleOnly.doc");
                                break;

                            case "Excel":                               
                                cv.ExportToDisk(ExportFormatType.ExcelWorkbook, "d:\\'" + combocompcode.Text + "'CompanyVehicleOnly.xls");
                                break;
                            case "PDF":
                                cv.ExportToDisk(ExportFormatType.PortableDocFormat, "d:\\'" + combocompcode.Text + "'CompanyVehicleOnly.pdf");
                                break;

                            case "CSV":
                                cv.ExportToDisk(ExportFormatType.CharacterSeparatedValues, "d:\\'" + combocompcode.Text + "'CompanyVehicleOnly.csv");
                                break;
                        }
                        combocompcode.SelectedIndex = -1; combocompcode.Text = "";
                    }
                    else
                    {
                        if (tabControl1.SelectedTab.Text == "TokenDetails")
                        {
                            switch (comboformate.Text)
                            {
                                case "Word":
                                    rd.ExportToDisk(ExportFormatType.WordForWindows, "d:\\'" + combocompcode.Text + "'TokenDetails.doc");
                                    break;

                                case "Excel":
                                    // formatType = ExportFormatType.Excel;
                                    rd.ExportToDisk(ExportFormatType.ExcelWorkbook, "d:\\'" + combocompcode.Text + "'TokenDetails.xls");
                                    break;

                                case "PDF":
                                    rd.ExportToDisk(ExportFormatType.PortableDocFormat, "d:\\'" + combocompcode.Text + "'TokenDetails.pdf");
                                    break;

                                case "CSV":
                                    rd.ExportToDisk(ExportFormatType.CharacterSeparatedValues, "d:\\'" + combocompcode.Text + "'TokenDetails.csv");
                                    break;
                            }
                        }
                        if (tabControl1.SelectedTab.Text == "Date Wise")
                        {
                            switch (comboformate.Text)
                            {
                                case "Word":
                                    datewise.ExportToDisk(ExportFormatType.WordForWindows, "d:\\'" + combocompcode.Text + "'DateWise.doc");
                                    break;

                                case "Excel":
                                    // formatType = ExportFormatType.Excel;
                                    datewise.ExportToDisk(ExportFormatType.ExcelWorkbook, "d:\\'" + combocompcode.Text + "'DateWise.xls");
                                    break;

                                case "PDF":
                                    datewise.ExportToDisk(ExportFormatType.PortableDocFormat, "d:\\'" + combocompcode.Text + "'DateWise.pdf");
                                    break;

                                case "CSV":
                                    datewise.ExportToDisk(ExportFormatType.CharacterSeparatedValues, "d:\\'" + combocompcode.Text + "'DateWise.csv");
                                    break;
                            }
                        }
                    }
                }
                else
                {

                }
            }
            else
            {
                MessageBox.Show("Pls Select Combo Box Value");
            }
        }

