'dd-MM-yyyy') and TO_DATE('" + todate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy')) X GROUP BY X.ASPTBLVEHTOKENID, X.COMPCODE,X.TOKENNO,  X.TOKENDATE,X.VEHICLENO, X.VEHTYPE ,X.FNAME, X.DEPT,  X.ITEMNAME,X.LITRES, X.FUELRATE2 ORDER BY 1";
